query:
-- Joe Payne's AE ID
SELECT id, name, joinDate FROM ae_profiles WHERE name LIKE '%Joe%' OR name LIKE '%Payne%';

-- Joe's deals in the deals table
SELECT COUNT(*) as deal_count FROM deals WHERE aeId = (SELECT id FROM ae_profiles WHERE name = 'Joe Payne');

-- Joe's monthly metrics
SELECT aeId, year, month, arrUsd, demosTotal, dialsTotal, connectedDials, connectionRate FROM monthly_metrics 
WHERE aeId = (SELECT id FROM ae_profiles WHERE name = 'Joe Payne')
ORDER BY year DESC, month DESC;

